import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { FaSearch, FaUser, FaUpload, FaInfoCircle, FaHome, FaGraduationCap, FaSignInAlt, FaUserPlus, FaBars, FaTimes, FaBook, FaLaptop, FaChartBar, FaBriefcase, FaCode } from 'react-icons/fa';

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState(null);
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setIsMenuOpen(false);
    setActiveDropdown(null);
  }, [location]);

  // ✅ Fetch courses when dropdown opens
  useEffect(() => {
    if (activeDropdown === 'courses') {
      fetchCourses();
    }
  }, [activeDropdown]);

  const fetchCourses = async () => {
    try {
      setLoading(true);
      const response = await fetch('http://localhost:5000/api/courses');
      const data = await response.json();
      
      if (data.success) {
        setCourses(data.courses.slice(0, 6)); // Limit to 6 courses
      }
    } catch (error) {
      console.error('Error fetching courses:', error);
      // Fallback courses if API fails
      setCourses([
        { id: 1, name: 'B.Tech', icon: '💻', code: 'BTECH' },
        { id: 2, name: 'BCA', icon: '📱', code: 'BCA' },
        { id: 3, name: 'BBA', icon: '📊', code: 'BBA' },
        { id: 4, name: 'MBA', icon: '🎓', code: 'MBA' },
        { id: 5, name: 'MCA', icon: '💼', code: 'MCA' },
        { id: 6, name: 'B.Com', icon: '💰', code: 'BCOM' },
      ]);
    } finally {
      setLoading(false);
    }
  };

  const navItems = [
    { name: 'Home', icon: <FaHome />, path: '/' },
    { name: 'Courses', icon: <FaGraduationCap />, path: '/courses', hasDropdown: true },
    { name: 'Upload', icon: <FaUpload />, path: '/upload' },
    { name: 'About', icon: <FaInfoCircle />, path: '/about' },
  ];

  const handleCourseClick = (courseId) => {
    navigate(`/course/${courseId}`);
    setActiveDropdown(null);
  };

  const styles = {
    navbar: {
      background: isScrolled ? 'rgba(79, 70, 229, 0.95)' : '#4f46e5',
      backdropFilter: isScrolled ? 'blur(10px)' : 'none',
      padding: '0.8rem 2rem',
      position: 'sticky',
      top: 0,
      zIndex: 1000,
      transition: 'all 0.3s ease',
      boxShadow: '0 2px 20px rgba(79, 70, 229, 0.3)'
    },
    container: {
      maxWidth: '1400px',
      margin: '0 auto',
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center'
    },
    logo: {
      color: 'white',
      fontSize: '1.5rem',
      fontWeight: 'bold',
      textDecoration: 'none',
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem'
    },
    navLinks: {
      display: 'flex',
      gap: '0.5rem',
      alignItems: 'center',
      marginLeft: '2rem'
    },
    link: {
      color: 'white',
      textDecoration: 'none',
      padding: '0.6rem 1.2rem',
      borderRadius: '8px',
      transition: 'all 0.3s',
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      fontSize: '0.95rem',
      fontWeight: '500',
      cursor: 'pointer',
      background: 'transparent',
      border: 'none',
      position: 'relative'
    },
    activeLink: {
      background: 'rgba(255, 255, 255, 0.2)',
    },
    dropdownWrapper: {
      position: 'relative'
    },
    dropdownMenu: {
      position: 'absolute',
      top: '100%',
      left: 0,
      minWidth: '300px',
      background: 'white',
      borderRadius: '12px',
      boxShadow: '0 10px 40px rgba(0,0,0,0.15)',
      padding: '1rem',
      marginTop: '0.5rem',
      zIndex: 1000,
      animation: 'slideDown 0.3s ease'
    },
    dropdownGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(2, 1fr)',
      gap: '0.5rem'
    },
    dropdownItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.8rem',
      padding: '0.8rem',
      borderRadius: '8px',
      cursor: 'pointer',
      transition: 'all 0.2s',
      background: '#f8fafc',
      border: '1px solid #e2e8f0'
    },
    courseIcon: {
      fontSize: '1.5rem',
      width: '40px',
      height: '40px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: '#4f46e5',
      color: 'white',
      borderRadius: '8px'
    },
    courseInfo: {
      flex: 1
    },
    courseName: {
      fontWeight: '600',
      color: '#1e293b',
      fontSize: '0.95rem'
    },
    courseCode: {
      fontSize: '0.7rem',
      color: '#64748b'
    },
    viewAllLink: {
      display: 'block',
      textAlign: 'center',
      padding: '0.8rem',
      marginTop: '0.8rem',
      color: '#4f46e5',
      textDecoration: 'none',
      fontWeight: '600',
      borderTop: '1px solid #e2e8f0'
    },
    authButtons: {
      display: 'flex',
      gap: '0.5rem',
      marginLeft: '1rem'
    },
    loginBtn: {
      background: 'transparent',
      border: '2px solid white',
      color: 'white',
      padding: '0.6rem 1.2rem',
      borderRadius: '8px',
      cursor: 'pointer',
      fontWeight: '500',
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      transition: 'all 0.3s'
    },
    registerBtn: {
      background: 'white',
      border: 'none',
      color: '#4f46e5',
      padding: '0.6rem 1.2rem',
      borderRadius: '8px',
      cursor: 'pointer',
      fontWeight: '500',
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      transition: 'all 0.3s'
    },
    mobileBtn: {
      display: 'none',
      background: 'transparent',
      border: 'none',
      color: 'white',
      fontSize: '1.5rem',
      cursor: 'pointer'
    },
    mobileMenu: {
      position: 'fixed',
      top: 0,
      right: isMenuOpen ? 0 : '-100%',
      width: '300px',
      height: '100vh',
      background: 'white',
      transition: 'right 0.3s ease',
      padding: '2rem',
      boxShadow: '-5px 0 30px rgba(0,0,0,0.1)',
      zIndex: 1001,
      overflowY: 'auto'
    },
    mobileCourseItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '1rem',
      padding: '1rem',
      borderBottom: '1px solid #e2e8f0',
      cursor: 'pointer'
    }
  };

  return (
    <nav style={styles.navbar}>
      <div style={styles.container}>
        {/* Logo */}
        <Link to="/" style={styles.logo}>
          <span style={{ fontSize: '2rem' }}>📚</span>
          <span>Study Portal</span>
        </Link>

        {/* Desktop Menu */}
        <div style={{ display: 'flex', alignItems: 'center', flex: 1, justifyContent: 'flex-end' }}>
          <div style={styles.navLinks}>
            {navItems.map(item => (
              item.hasDropdown ? (
                <div key={item.name} style={styles.dropdownWrapper}>
                  <button
                    style={{
                      ...styles.link,
                      ...(activeDropdown === 'courses' ? styles.activeLink : {})
                    }}
                    onClick={() => setActiveDropdown(activeDropdown === 'courses' ? null : 'courses')}
                    onMouseEnter={() => setActiveDropdown('courses')}
                  >
                    {item.icon} {item.name} <span style={{ fontSize: '0.7rem' }}>▼</span>
                  </button>

                  {/* Dropdown Menu */}
                  {activeDropdown === 'courses' && (
                    <div 
                      style={styles.dropdownMenu}
                      onMouseLeave={() => setActiveDropdown(null)}
                    >
                      {loading ? (
                        <div style={{ textAlign: 'center', padding: '1rem' }}>Loading...</div>
                      ) : (
                        <>
                          <div style={styles.dropdownGrid}>
                            {courses.map(course => (
                              <div
                                key={course.id}
                                style={styles.dropdownItem}
                                onClick={() => handleCourseClick(course.id)}
                                onMouseEnter={(e) => {
                                  e.currentTarget.style.background = '#e0e7ff';
                                  e.currentTarget.style.borderColor = '#4f46e5';
                                }}
                                onMouseLeave={(e) => {
                                  e.currentTarget.style.background = '#f8fafc';
                                  e.currentTarget.style.borderColor = '#e2e8f0';
                                }}
                              >
                                <div style={styles.courseIcon}>
                                  {course.icon || '📚'}
                                </div>
                                <div style={styles.courseInfo}>
                                  <div style={styles.courseName}>{course.name}</div>
                                  <div style={styles.courseCode}>{course.code || 'Course'}</div>
                                </div>
                              </div>
                            ))}
                          </div>
                          <Link to="/courses" style={styles.viewAllLink} onClick={() => setActiveDropdown(null)}>
                            View All Courses →
                          </Link>
                        </>
                      )}
                    </div>
                  )}
                </div>
              ) : (
                <Link
                  key={item.name}
                  to={item.path}
                  style={{
                    ...styles.link,
                    ...(location.pathname === item.path ? styles.activeLink : {})
                  }}
                >
                  {item.icon} {item.name}
                </Link>
              )
            ))}
          </div>

          {/* Auth Buttons */}
          <div style={styles.authButtons}>
            <button style={styles.loginBtn} onClick={() => navigate('/login')}>
              <FaSignInAlt /> Login
            </button>
            <button style={styles.registerBtn} onClick={() => navigate('/register')}>
              <FaUserPlus /> Register
            </button>
          </div>
        </div>

        {/* Mobile Menu Button */}
        <button style={styles.mobileBtn} onClick={() => setIsMenuOpen(!isMenuOpen)}>
          {isMenuOpen ? <FaTimes /> : <FaBars />}
        </button>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <>
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'rgba(0,0,0,0.5)',
            zIndex: 1000
          }} onClick={() => setIsMenuOpen(false)} />
          
          <div style={styles.mobileMenu}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
              <h3 style={{ color: '#4f46e5' }}>Menu</h3>
              <button onClick={() => setIsMenuOpen(false)} style={{ background: 'none', border: 'none', fontSize: '1.2rem' }}>
                <FaTimes />
              </button>
            </div>

            {navItems.map(item => (
              <div key={item.name}>
                {item.hasDropdown ? (
                  <>
                    <div style={{ padding: '1rem', fontWeight: '600', color: '#4f46e5' }}>
                      {item.icon} {item.name}
                    </div>
                    <div style={{ paddingLeft: '1rem' }}>
                      {courses.map(course => (
                        <div
                          key={course.id}
                          style={styles.mobileCourseItem}
                          onClick={() => {
                            handleCourseClick(course.id);
                            setIsMenuOpen(false);
                          }}
                        >
                          <span style={{ fontSize: '1.2rem' }}>{course.icon || '📚'}</span>
                          <span>{course.name}</span>
                        </div>
                      ))}
                    </div>
                  </>
                ) : (
                  <Link
                    to={item.path}
                    style={{
                      display: 'block',
                      padding: '1rem',
                      color: '#333',
                      textDecoration: 'none',
                      borderBottom: '1px solid #eee'
                    }}
                    onClick={() => setIsMenuOpen(false)}
                  >
                    {item.icon} {item.name}
                  </Link>
                )}
              </div>
            ))}

            <div style={{ marginTop: '2rem' }}>
              <button 
                style={{ ...styles.loginBtn, width: '100%', marginBottom: '1rem', color: '#4f46e5', background: 'transparent' }}
                onClick={() => {
                  navigate('/login');
                  setIsMenuOpen(false);
                }}
              >
                <FaSignInAlt /> Login
              </button>
              <button 
                style={{ ...styles.registerBtn, width: '100%', background: '#4f46e5', color: 'white' }}
                onClick={() => {
                  navigate('/register');
                  setIsMenuOpen(false);
                }}
              >
                <FaUserPlus /> Register
              </button>
            </div>
          </div>
        </>
      )}

      {/* CSS Animations */}
      <style>
        {`
          @keyframes slideDown {
            from {
              opacity: 0;
              transform: translateY(-10px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }
          
          button:hover {
            transform: translateY(-2px);
          }
        `}
      </style>
    </nav>
  );
};

export default Navbar;
